// This node determines which spam folders to check
// based on your partner email providers

const partners = [
  { label: 'Gmail', spamFolder: '[Gmail]/Spam', provider: 'gmail' },
  { label: 'Outlook', spamFolder: 'Junk', provider: 'outlook' },
  { label: 'Yahoo', spamFolder: 'Bulk Mail', provider: 'yahoo' }
];

// Output all partners to check in parallel
return partners.map(p => ({ json: p }));

// =============================================
// SPAM RESCUE ACTION
// =============================================
// This is the MOST POWERFUL warmup signal.
// Moving email from Spam → Inbox tells the
// provider: "This sender is legitimate!"
//
// HOW TO COMPLETE THIS:
//
// For Gmail partners:
//   Add a "Gmail" node after this with:
//   - Action: Modify Message Labels
//   - Remove Labels: SPAM
//   - Add Labels: INBOX, IMPORTANT
//
// For Outlook partners:
//   Add a "Microsoft Outlook" node:
//   - Action: Move Message
//   - Destination: Inbox
//
// For Yahoo/others:
//   Use HTTP Request to their API
//   or manually set up filters

const email = $input.first().json;
const fromField = email.from || '';

return [{
  json: {
    action: 'RESCUE_FROM_SPAM',
    from: fromField,
    subject: email.subject || '(no subject)',
    messageId: email.messageId || '',
    rescuedAt: new Date().toISOString(),
    priority: 'HIGH',
    note: 'This email from bygweb.com was found in spam and needs to be moved to inbox'
  }
}];

// Log rescue for monitoring
// If you see many rescues, it means:
// 1. DNS (SPF/DKIM/DMARC) may need fixing
// 2. Sending volume may be too high
// 3. Email content may be triggering filters

const data = $input.first().json;

const staticData = $getWorkflowStaticData('global');
if (!staticData.rescueCount) staticData.rescueCount = 0;
staticData.rescueCount++;

return [{
  json: {
    ...data,
    totalRescues: staticData.rescueCount,
    healthWarning: staticData.rescueCount > 10 
      ? 'HIGH SPAM RATE - Check DNS records and reduce sending volume!'
      : 'Normal - keep monitoring'
  }
}];
